    "SupertrendOpts": {
        "fqn": "SupertrendOpts",
        "kind": "type",
        "title": "SupertrendOpts",
        "summary": "Options bag for `ta.supertrend`. `length` is the ATR period\n(default `10`); `multiplier` scales the band offset from `hl2`\n(default `3`). `offset` shifts the read window backwards\n(PLAN.md §9.1 — accepted on the surface). The source is hard-coded\nto `hl2` (Pine-canonical Supertrend); a `source` opt could land in\na follow-up.",
        "examples": [
            "const opts: SupertrendOpts = { length: 10, multiplier: 3 };"
        ],
        "since": "0.2",
        "stability": "experimental"
    },
    "SupertrendResult": {
        "fqn": "SupertrendResult",
        "kind": "type",
        "title": "SupertrendResult",
        "summary": "The two-series result of `ta.supertrend` — the trailing-stop\n`line` (the active final band per current direction) and the\nper-bar `direction` (`+1` uptrend → `line = finalLower`,\n`-1` downtrend → `line = finalUpper`, NaN during warmup).",
        "examples": [
            "const s = ta.supertrend({ length: 10, multiplier: 3 });\nplot(s.line);"
        ],
        "since": "0.2",
        "stability": "experimental"
    },
